#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=500005;
string s;
int mx[N][5],mn[N][5],cnt=1,ans;
void dfs(int x)
{
	if(s[x]=='0')
	{
		mx[x][0]=mn[x][0]=1;
		return ;
	}
	dfs(++cnt);
	if(s[x]=='1')
	{
		mx[x][0]=max(mx[x+1][1],mx[x+1][2])+1;
		mx[x][1]=max(mx[x+1][0],mx[x+1][2]);
		mx[x][2]=max(mx[x+1][0],mx[x+1][1]);
		mn[x][0]=min(mn[x+1][1],mn[x+1][2])+1;
		mn[x][1]=min(mn[x+1][0],mn[x+1][2]);
		mn[x][2]=min(mn[x+1][0],mn[x+1][1]);
	}
	else
	{
		int tmp=++cnt;
		dfs(cnt);
		mx[x][0]=max(mx[x+1][1]+mx[tmp][2],mx[x+1][2]+mx[tmp][1])+1;
		mx[x][1]=max(mx[x+1][0]+mx[tmp][2],mx[x+1][2]+mx[tmp][0]);
		mx[x][2]=max(mx[x+1][0]+mx[tmp][1],mx[x+1][1]+mx[tmp][0]);
		mn[x][0]=min(mn[x+1][1]+mn[tmp][2],mn[x+1][2]+mn[tmp][1])+1;
		mn[x][1]=min(mn[x+1][0]+mn[tmp][2],mn[x+1][2]+mn[tmp][0]);
		mn[x][2]=min(mn[x+1][0]+mn[tmp][1],mn[x+1][1]+mn[tmp][0]);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>s;
	s=" "+s;
	dfs(cnt);
	cout<<max(mx[1][0],max(mx[1][1],mx[1][2]))<<" "<<min(mx[1][0],min(mn[1][1],mn[1][2]));
	return 0;
}
